const body = $json.body || {};
const query = String(body.query || body.topic || '').trim();
const requestedLimit = Number(body.limit ?? 8);

return {
  run_timestamp: $json.run_timestamp || new Date().toISOString(),
  notion_token: $json.notion_token,
  memory_db_id: $json.memory_db_id,
  query,
  limit: Number.isFinite(requestedLimit) ? Math.max(1, Math.min(20, requestedLimit)) : 8
};

function plainText(rich) {
  if (!Array.isArray(rich)) return '';
  return rich.map((x) => x.plain_text || '').join('').trim();
}

function getTitle(props, key) {
  const value = props[key];
  if (!value || !Array.isArray(value.title)) return '';
  return plainText(value.title);
}

function getRich(props, key) {
  const value = props[key];
  if (!value || !Array.isArray(value.rich_text)) return '';
  return plainText(value.rich_text);
}

function getSelect(props, key) {
  const value = props[key];
  return value && value.select ? String(value.select.name || '').trim() : '';
}

function getNumber(props, key) {
  const value = props[key];
  return value && typeof value.number === 'number' ? value.number : null;
}

function getDate(props, key) {
  const value = props[key];
  return value && value.date ? value.date.start : null;
}

const query = ($json.query || '').trim();
const results = Array.isArray($json.results) ? $json.results : [];
const now = new Date();

const parsed = results.map((page) => {
  const props = page.properties || {};
  const subject = getTitle(props, 'Name') || getRich(props, 'subject') || 'untitled memory';
  const summary = getRich(props, 'summary');
  const type = getSelect(props, 'type') || 'fact';
  const lastSeen = getDate(props, 'last_seen');
  const staleAfter = getNumber(props, 'stale_after_days');

  let ageDays = null;
  if (lastSeen) {
    const then = new Date(lastSeen);
    if (!Number.isNaN(then.getTime())) {
      ageDays = Math.floor((now.getTime() - then.getTime()) / (1000 * 60 * 60 * 24));
    }
  }

  const isStale = Number.isFinite(ageDays) && Number.isFinite(staleAfter) && ageDays > staleAfter;

  return {
    type,
    subject,
    summary,
    ageDays,
    staleAfter,
    isStale
  };
});

const fresh = parsed.filter((m) => !m.isStale);
const stale = parsed.filter((m) => m.isStale);
const ordered = [...fresh, ...stale].slice(0, Number($json.limit || 8));

const bullets = ordered.map((m) => {
  const staleFlag = m.isStale ? '[STALE] ' : '';
  const age = Number.isFinite(m.ageDays) ? `${m.ageDays}d ago` : 'no last_seen';
  const detail = m.summary ? ` - ${m.summary}` : '';
  return `- ${staleFlag}[${m.type}] ${m.subject} (${age})${detail}`;
}).join('\n');

const message = `[system] memory recall brief\n\nQuery: ${query || '(none)'}\nMatches: ${parsed.length}\nFresh: ${fresh.length}\nStale: ${stale.length}\n\n${bullets || '- No active memory found for this query.'}\n\n${stale.length ? 'Note: stale memories are marked and should be corrected or archived.' : 'Note: no stale memory detected in this brief.'}`;

return {
  message,
  query,
  matches: parsed.length,
  stale: stale.length
};
